package com.hospital.management.validation;import com.hospital.management.model.Department;import org.junit.jupiter.api.Test;import static org.junit.jupiter.api.Assertions.*;
class DepartmentValidatorTest{private final DepartmentValidator v=new DepartmentValidator();private Department d(String n){return new Department(null,n,"description","location","ACTIVE");}@Test void valid(){assertFalse(v.validate(d("Cardiology")).hasErrors());}@Test void blank(){assertNotNull(v.validate(d(" ")).getError("departmentName"));}@Test void shortName(){assertNotNull(v.validate(d("A")).getError("departmentName"));}@Test void longName(){assertNotNull(v.validate(d("A".repeat(101))).getError("departmentName"));}@Test void longDescription(){Department d=d("Good");d.setDescription("x".repeat(501));assertNotNull(v.validate(d).getError("description"));}@Test void longLocation(){Department d=d("Good");d.setLocation("x".repeat(151));assertNotNull(v.validate(d).getError("location"));}@Test void invalidStatus(){Department d=d("Good");d.setStatus("DELETED");assertNotNull(v.validate(d).getError("status"));}}
